var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어때? 관리국에서 운영하는 무료 급식소야.","JPN":"どう？　管理局で運営してる炊き出しだよ。","ENG":"What do you say? It’s a free soup kitchen run by the Administration.","TWN":"怎麼樣？這裡是由管理局經營的免費飯館。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"이런 곳도 있었네.","JPN":"こんなところもあったんだね。","ENG":"I didn’t know such a place existed.","TWN":"竟然有這種地方。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"훗. 물론 이런 고급 정보를 누구나 다 아는 건 아니지. 나 만나서 행운인 줄 알아.","JPN":"ふっ。もちろんこんな高級情報を誰でも知ってるわけじゃないんだ。私に出会えて幸運だと思いなよ。","ENG":"Hmph! You’re lucky to have met me. Who else would give you such valuable information?","TWN":"呵，這麼高級的地方可不是誰都知道的，遇見我算你幸運！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아. 줄 빠졌다. 빨리 안 가면 아저씨들한테 다 뺏긴다.","JPN":"あ。列が減った。早く行かないと、おじさんたちに全部取られちゃう。","ENG":"Hey look, the lines moving. If we don’t get there fast, everyone else is gonna take all the food.","TWN":"欸，我們脫隊了，趕快跟上，否則大叔們會把菜都搶光的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SPEAR_MAID_DREAM_FAKE","text":{"KOREA":"톰! 새치기하는 거 다 봤어. 맨밥만 주기 전에 얌전히 뒤로 가.","JPN":"トム！　割り込んだの見てたよ。大人しく後ろに行かないとおかずあげないから。","ENG":"Tom! I saw you cutting in line! Go to the back of the line or I’m only gonna give you rice!","TWN":"湯姆！我有看到你插隊，乖乖回去排隊，否則別怪我只給你白飯！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TOM_NPC_DREAM_NULL","text":{"KOREA":"쳇. 하여간 예리하다니까. 한 번을 안 넘어가.","JPN":"チッ。まったく、鋭いぜ。一度も大目に見てくれねえ。","ENG":"Tch! Her and her keen eye... How does she catch me every time?","TWN":"嘖，眼睛這麼利，每次都逃不過你的法眼！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_MAID_DREAM_FAKE","text":{"KOREA":"너처럼 티 팍팍 내면서 새치기하는 인간도 드물거든?","JPN":"あんたのように一目で割り込みってわかるやつもそうそういないよ？","ENG":"Well, not everyone cuts in line as blatantly as you!","TWN":"像你插隊插得這麼明顯的人也算少見啦？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_MAID_DREAM_FAKE","text":{"KOREA":"말 잘 들으면 <color=#ffd34c>특별 수제 소스</color> 따로 퍼 줄게. 이번에 만든 회심의 역작이야.","JPN":"言うことよく聞いたら、<color=#ffd34c>特製手作りソース</color>をあげる。今回作った会心の力作なんだ。","ENG":"Behave, and I’ll give you more of my <color=#ffd34c>special sauce</color>. It’s my greatest batch yet!","TWN":"你聽話的話，我就另外裝一些<color=#ffd34c>特製醬料</color>給你，這次的成果很讚喔！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TOM_NPC_DREAM_NULL","text":{"KOREA":"어…… 나 다시 새치기하면 안 될까?","JPN":"え……俺また割り込んじゃダメかな？","ENG":"Uh... C-can I just cut back in line instead?","TWN":"那個……我選擇插隊可以嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그렇게 깨작깨작 먹다간 저기 빨간 머리 봉사자님한테 등짝 맞을지도 모른다?","JPN":"そうやってしぶしぶ食べてると、あっちの赤髪のボランティアさんに叩かれるかもしれないよ？","ENG":"You keep eating like that and that red-haired volunteer’s gonna give you an earful!","TWN":"你這樣挑食的話，等下那個紅髮姊姊會打人喔！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"딱 봐도 손이 엄청 매워 보이는데.","JPN":"パッと見、叩かれたらめっちゃ痛そう。","ENG":"Just look at her. Doesn’t she look like she’ll spit fire?","TWN":"看也知道她的手勁應該很厲害吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"……으응.","JPN":"……うん。","ENG":"…Okay.","TWN":"……嗯嗯。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"오늘따라 씹히는 게 적긴 하네. 치사하게 소시지도 두 개씩 밖에 안 주고.","JPN":"今日は具が少ないなぁ。ソーセージも二つずつしかくれないなんて、ケチくさい。","ENG":"I guess today’s menu isn’t that great. Plus she only gave me two sausages.","TWN":"今天的東西好少，連小香腸都只給二根，真是小氣！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"내 거 먹을래?","JPN":"私のも食べる？","ENG":"Do you want mine?","TWN":"你要吃我的嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……소시지?","JPN":"……ソーセージ？","ENG":"Your sausages?","TWN":"……你說小香腸？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"으응. 별로 입맛이 없어서.","JPN":"うん。あんまり食欲なくて。","ENG":"Yes... I’m not that hungry.","TWN":"嗯嗯，我吃不太下。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"소시지를 준다고? 두 개밖에 없는 걸?","JPN":"ソーセージくれるの？　二つしかないのに？","ENG":"You’re giving me your sausages? But you only have two?","TWN":"你要把小香腸給我？一人只有二根欸？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"글린다가 다 먹어도 좋아.","JPN":"グリンダが全部食べてもいいよ。","ENG":"You can have all if you want, Glinda.","TWN":"都給你吃吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루, 너…… 생각보다 괜찮은 애였구나.","JPN":"ルル、アンタ……思ったよりいい子だったんだね。","ENG":"Lulu, you’re... a really good friend, aren’t you?","TWN":"露露你……是好孩子欸！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"이것도 글린다 먹어.","JPN":"これもグリンダが食べて。","ENG":"Here, Glinda. You can have this too.","TWN":"這也給你吃。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"이것도.","JPN":"これも。","ENG":"And this.","TWN":"還有這個。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"이것도. 밥도 좀 덜어줄까?","JPN":"これも。ご飯も分けてあげようか？","ENG":"And this too. Do you want more rice?","TWN":"跟這個，飯也給你一點嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이제 그만 줘도 돼. 뭘 그렇게 다 주냐?","JPN":"もういいよ。なんでそんなに全部くれるんだよ？","ENG":"I think this is enough. But why are you giving me almost all of your meal?","TWN":"不要再給我了啦，幹嘛什麼都給我？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"잘 먹으니까 보기 좋아서.","JPN":"よく食べるから見てると嬉しいの。","ENG":"Because I like watching you eat.","TWN":"看你吃得很開心。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"왠지 본 적도 없는 우리 할머니가 생각나네.","JPN":"なんだか会ったことはないけど、おばあちゃんを思い出すなぁ。","ENG":"You somehow remind me of Grandma that I’ve never met...","TWN":"怎麼令我突然想起素未謀面的奶奶？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPEAR_MAID_DREAM_FAKE","text":{"KOREA":"무슨 짓이야?! 여기가 어디라고 무장한 녀석들이 함부로 들어와?","JPN":"何してるの！？　武装した奴らがなんでむやみに入ってくるわけ？","ENG":"What’s the meaning of this?! This isn’t a place for armed men to just barge in!","TWN":"做什麼？！你們把這裡當成什麼地方，竟敢拿著武器擅闖進來？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"거 참. 막고 있는 건 그쪽이잖아? 얌전히 우리 애들만 데려간다니까?","JPN":"まあまあ。道を塞いでんのはそっちだろ？　ウチの子たちだけ連れて消えるからさ。","ENG":"Ugh. You’re the one obstructing justice right now! We’ll leave quietly once we have our culprits!","TWN":"真是的，誰叫你擋路，我們只想把人帶走，沒有要惹事。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAR_MAID_DREAM_FAKE","text":{"KOREA":"행패 부릴 생각 말고 꺼지시지? 매운 맛 보여주기 전에!","JPN":"乱暴する気なら出てってくれる？　痛い目に合う前に！","ENG":"If you’re gonna cause a scene, I suggest you leave before I give you a piece of my spicy mind!","TWN":"少在這耍流氓，快滾！否則別怪我不客氣！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"말이 안 통하네. 여기 다 엎어 버려?","JPN":"話が通じねえな。ここ全部荒してやろうか？","ENG":"You don’t get it, do you?! Do you want us to shut this place down, huh?!","TWN":"講不通欸！要我砸場嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……! 지원팀?","JPN":"……！　応援班？","ENG":"...! The support team?","TWN":"……！支援組？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어, 어떻게 벌써?","JPN":"ど、どうやってこんな早く？","ENG":"H-how did they already find us?","TWN":"這…這麼快就找到這裡來？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이 정도 거리면…… 도망가도 소용없겠네.","JPN":"このくらいの距離なら……逃げても無駄だろうね。","ENG":"We’re too close... Running away will be useless.","TWN":"這樣的距離……就算逃跑也會被抓到。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"곧바로 죽거나, 최소 벌…….","JPN":"すぐ殺されるか、少なくともお仕置き……","ENG":"It’s either we die on the spot, or get pun─","TWN":"被抓到後不是立刻受死，起碼也會受罰……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"벌……?","JPN":"お仕置き……？","ENG":"Pun...?","TWN":"受罰……？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"다시 벌받긴 죽어도 싫은데…….","JPN":"もうお仕置きなんて死んでもイヤなのに……","ENG":"But I’d rather die than receive punishment...","TWN":"我死也不想再受罰……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"글린다, 괜찮아?","JPN":"グリンダ、大丈夫？","ENG":"Glinda, are you okay?","TWN":"格琳達，你還好嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"괜찮겠냐? 이게 다 너 때문이잖아!","JPN":"大丈夫なわけないでしょ？　これも全部アンタのせいだよ！","ENG":"What do you think? This is all because of you!","TWN":"好什麼好？這全都是你害的！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"미안해…….","JPN":"ごめん……","ENG":"Sorry...","TWN":"對不起……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그 놈의 미안하다는 소리는 그만 좀 하고!","JPN":"ごめんはもういい！","ENG":"Will you quit saying sorry all the time?!","TWN":"不要再跟我說對不起！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이게 뭐야…… 너 때문에 되는 게 하나도 없어…….","JPN":"何なの……アンタのせいで何もかもダメになって……","ENG":"See...? I can’t even catch a break because of you...","TWN":"搞什麼……你真是成事不足……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"글린다. 진정해. 내가…… 갈 테니까.","JPN":"グリンダ。落ち着いて。私が……行くから。","ENG":"Glinda. Calm down. I’ll... go.","TWN":"格琳達，你冷靜點，我……過去。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"간다는 소리도 좀 작작……","JPN":"行くって話もいい加減……","ENG":"Will you please stop saying that you’ll─","TWN":"到底要去哪裡……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어? 어딜 간다는 거야? 설마…….","JPN":"え？　どこ行くって？　まさか……","ENG":"Huh? What do you mean by that? You’re not saying...","TWN":"嗯？你是要去哪？該不會……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"가서 오해를 풀면, 글린다는 무사히 원래 자리로 돌아갈 수 있지 않을까?","JPN":"誤解を解けば、グリンダは無事に元のところに戻れるんじゃない？","ENG":"I’ll go and clear up the misunderstanding. Then you’ll be able to go back to your normal life, right?","TWN":"我過去解開誤會，他們應該就會讓你復職吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"네 말대로 나 때문에 벌어진 일이니까……. 내가 되돌릴게.","JPN":"グリンダの言う通り、私のせいでこんなことになったんだから……私が取り戻すよ。","ENG":"I'm entirely to blame for this... So let me fix it.","TWN":"你說這些事是因我而起的……那就由我去挽救。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……허세도 부릴 줄 아네.","JPN":"……強がりも言えるのね。","ENG":"Look at you acting all tough...","TWN":"……真會說大話。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"됐어.","JPN":"もういいよ。","ENG":"Forget it.","TWN":"算了吧！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"으응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"현실적으로 그게 되겠어? 가서 얘기한다고 쟤들이 날 무사하게 내버려둘 것 같아?","JPN":"現実的に無理でしょ？　話し合っても、あいつらが私を無事に放っておくわけないし。","ENG":"Do you really think that’s possible? That they’ll just leave me alone after you talk to them?","TWN":"你覺得有可能嗎？有可能你去說兩句，他們就願意放過我嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"순진한 거야, 멍청한 거야. 되도 않는 허세 그만 부리고 어떻게든 도망이라도 가 보자고.","JPN":"純粋なのか、バカなのか。下手な強がりはやめてなんとか逃げてみよう。","ENG":"Don’t be so naive. Stop trying to be tough and let’s try to find a way outta this mess.","TWN":"你是太傻還是太天真？不要再說那些不切實際的話，還是想辦法快逃吧！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"붙잡히기 전까지 시간을 벌 수 있을……","JPN":"捕まるまで時間を稼げるはず……","ENG":"We gotta buy some time before they ca─","TWN":"趁現在還能爭取一點時間……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"고작 몇 초 벌자고 귀찮게 굴게?","JPN":"たった数秒のために煩わしくさせるつもりか？","ENG":"What? You think a couple of seconds is worth all this?","TWN":"也才幾秒而已，有需要這麼麻煩嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"뭐, 뭐야!","JPN":"な、なに！","ENG":"W-what?","TWN":"想嚇死誰！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"애 데리고 네가 도망쳐 봤자 우리 손아귀지.","JPN":"そいつをつれて逃げたって、俺らの手の内なんだよ。","ENG":"You can run with her, but you can’t hide from us.","TWN":"你帶著她是想逃去哪？再怎麼逃也逃不過我們的五指山的！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"바쁘신 자원 봉사자 분들 방해하지 말고 조용히 움직이자?","JPN":"お忙しいボランティアの方々の邪魔しないで、大人しくついてこいよ？","ENG":"So how about we stop bothering the good folks working here and go quietly, hmm?","TWN":"志工那麼忙，還是別打擾他們，乖乖跟我們走吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"저, 저 빨간 머리 눈 치켜 뜨는 것 좀 봐. 어우.","JPN":"ほら、あの赤髪の目がつりあがってんだろ。こわっ。","ENG":"Ugh... Just look at the red-head glaring daggers at us.","TWN":"你們看，那個紅頭髮的眼睛瞪得有多大，好嚇人喔～"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아, 알겠으니까 이것 좀 놓고……!","JPN":"わ、わかったからこれ置いて……！","ENG":"F-fine! Could you just─!","TWN":"好，我跟你們走，但可以先把這個放下……！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}}]`);export{e as default};